#include<bits/stdc++.h>
using namespace std;
long long mp[410][410],dp[410][410],c[5050][5050];
const long long mod=998244353;
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    n*=2;
    for(long long i=1;i<=m;i++)
    {
        long long x,y;
        scanf("%lld%lld",&x,&y);
        mp[x][y]=mp[y][x]=1;
        if(abs(x-y)==1)
        {
            dp[x][y]=dp[y][x]=1;
        }
    }
    c[0][0]=1;
    for(long long i=1;i<=n+1;i++)
    {
        for(long long j=0;j<=i;j++)
        {
            if(j==0)
            {
                c[i][j]=1;
                continue;
            }
            c[i][j]=c[i-1][j]+c[i-1][j-1];
            c[i][j]%=mod;
        }
    }
    for(long long len=2;len<=n;len+=2)
    {
        for(long long l=1,r=len;r<=n;l++,r++)
        {
            if(mp[l][r])
            {
                dp[l][r]=dp[l+1][r-1];
            }
            for(long long k=l+1;k+1<r;k+=2)
            {
                if(!mp[k+1][r])
                {
                    continue;
                }
                dp[l][r]+=dp[l][k]%mod*dp[k+2][r-1]%mod*c[len/2][(k-l+1)/2]%mod;
                dp[l][r]%=mod;
            }
        }
    }
    printf("%lld",dp[1][n]);
    return 0;
}
